#!/bin/bash\n# Health check for sast-configuration skill\n\necho "🔍 Validating sast-configuration..."\n\n# Check if SKILL.md exists\nif [ -f "SKILL.md" ]; then\n    echo "✅ SKILL.md found."\nelse\n    echo "❌ SKILL.md missing!"\n    exit 1\nfi\n\n# Check for python3\nif command -v python3 &> /dev/null; then\n    echo "✅ Python3 available."\nelse\n    echo "❌ Python3 not found - required for SAST tools."\n    exit 1\nfi\n\n# Check for semgrep\nif command -v semgrep &> /dev/null; then\n    echo "✅ Semgrep available."\nelse\n    echo "⚠️  Semgrep not found - install with: pip install semgrep"\nfi\n\n# Check for codeql\nif command -v codeql &> /dev/null; then\n    echo "✅ CodeQL available."\nelse\n    echo "⚠️  CodeQL not found - install with: gh extension install github/gh-codeql"\nfi\n\necho "🚀 sast-configuration is ready for SAST tool setup."\nexit 0
